// frontend/src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import axios from "axios";

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    axios.get("/api/dashboard-stats")
      .then(res => setStats(res.data))
      .catch(err => console.error("Failed to fetch stats", err));
  }, []);

  return (
    <div>
      <h1>📊 Dashboard</h1>
      {stats ? (
        <>
          <p>Free Rooms: {stats.pieChart.free}</p>
          <p>Occupied Rooms: {stats.pieChart.occupied}</p>
          <p>Labs: {stats.resourceSummary.labs}</p>
          <p>Projectors: {stats.resourceSummary.projectors}</p>
          <p>Classrooms: {stats.resourceSummary.classrooms}</p>
          <h3>Free Rooms per Day</h3>
          <ul>
            {Object.entries(stats.barChart).map(([day, count]) => (
              <li key={day}>{day}: {count}</li>
            ))}
          </ul>
        </>
      ) : (
        <p>Loading stats...</p>
      )}
    </div>
  );
};

export default Dashboard;
